// Use the `eval` function to parse the input string and return the result.
// Handle cases where the input string is empty or contains invalid characters by checking for null or undefined values.
function calculate(s) {
  if (s === '') return null;
  if (s.includes(' ')) return null;
  try {
    return eval(s);
  } catch (e) {
    return null;
  }
}

